    ],
    total: 660, status: 'confirmed',
    placedAt: new Date(Date.now() - 1 * 60000).toISOString(),
    note: '',
  },
];

const STATUS_FLOW = ['confirmed', 'preparing', 'ready', 'served'];

const STATUS_CFG = {
  confirmed: { label: 'Confirmed', bg: 'bg-blue-100',   text: 'text-blue-700',   border: 'border-blue-200',  dot: 'bg-blue-500'   },
  preparing: { label: 'Preparing', bg: 'bg-amber-100',  text: 'text-amber-700',  border: 'border-amber-300', dot: 'bg-amber-500'  },
  ready:     { label: 'Ready!',    bg: 'bg-green-100',  text: 'text-green-700',  border: 'border-green-300', dot: 'bg-green-500'  },
  served:    { label: 'Served',    bg: 'bg-gray-100',   text: 'text-gray-500',   border: 'border-gray-200',  dot: 'bg-gray-400'   },
};

const NEXT_ACTION = {
  confirmed: { label: 'Start Preparing', icon: '👨‍🍳', next: 'preparing', color: 'bg-amber-500 hover:bg-amber-600' },
  preparing: { label: 'Mark Ready',      icon: '✅',    next: 'ready',     color: 'bg-green-600 hover:bg-green-700' },
  ready:     { label: 'Mark Served',     icon: '🍽️',   next: 'served',    color: 'bg-gray-600  hover:bg-gray-700'  },
  served:    { label: 'Completed',        icon: '🎉',   next: null,        color: 'bg-gray-300 cursor-not-allowed'  },
};

function timeAgo(iso) {
  const diff = Math.floor((Date.now() - new Date(iso).getTime()) / 60000);
  if (diff < 1) return 'just now';
  return `${diff} min ago`;
}

export default function LiveOrders() {
  const [orders, setOrders]         = useState(INITIAL_ORDERS);
  const [filterStatus, setFilter]   = useState('all');
  const [calledToken, setCalledToken] = useState(null);
  const [expandedId, setExpandedId]  = useState(null);

  const updateStatus = (orderId, nextStatus) => {
    setOrders(prev =>
      prev.map(o => o.id === orderId ? { ...o, status: nextStatus } : o)
    );
  };

  const callToken = (token, table) => {
    setCalledToken({ token, table });
    // In production: emit socket event here
    // socket.emit('call_token', { token, table, restaurantId });
    setTimeout(() => setCalledToken(null), 4000);
  };

  const filtered = orders.filter(o =>
    filterStatus === 'all' ? o.status !== 'served' :
    filterStatus === 'served' ? o.status === 'served' :
    o.status === filterStatus
  );

  const counts = {
    confirmed: orders.filter(o => o.status === 'confirmed').length,
    preparing: orders.filter(o => o.status === 'preparing').length,
    ready:     orders.filter(o => o.status === 'ready').length,
    served:    orders.filter(o => o.status === 'served').length,
  };

  return (
    <div className="flex flex-col gap-5">

      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-xl font-bold text-gray-900">Live Order Queue</h2>
          <p className="text-sm text-gray-500 mt-0.5">
            {orders.filter(o => o.status !== 'served').length} active orders
          </p>
        </div>
        <div className="flex items-center gap-2 text-xs bg-green-50 border border-green-200 text-green-700 px-3 py-2 rounded-full font-medium">
          <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse" />
          Live updating
        </div>
      </div>

      {/* Token called banner */}
      {calledToken && (
        <div className="bg-green-600 text-white rounded-2xl px-6 py-4 flex items-center gap-4 animate-bounce shadow-lg">
          <span className="text-3xl">📢</span>
          <div>
            <p className="font-bold text-lg">TOKEN #{calledToken.token} — YOUR ORDER IS READY!</p>
            <p className="text-green-100 text-sm">
              {calledToken.table === 'Takeaway'
                ? 'Please collect your order from the counter.'
                : `Please come to ${calledToken.table} — your food is being served.`}
            </p>
          </div>
        </div>
      )}

      {/* Status summary pills */}
      <div className="grid grid-cols-4 gap-3">
        {[
          { key: 'confirmed', label: 'Confirmed', icon: '📋' },
          { key: 'preparing', label: 'Preparing', icon: '👨‍🍳' },
          { key: 'ready',     label: 'Ready',     icon: '✅' },
          { key: 'served',    label: 'Served',    icon: '🍽️' },
        ].map(s => {
          const cfg = STATUS_CFG[s.key];
          return (
            <button
              key={s.key}
              onClick={() => setFilter(filterStatus === s.key ? 'all' : s.key)}
              className={`rounded-xl p-4 border text-left transition-all ${
                filterStatus === s.key
                  ? `${cfg.bg} ${cfg.border} shadow-sm`
                  : 'bg-white border-gray-200 hover:border-gray-300'
              }`}
            >
              <div className="text-2xl mb-1">{s.icon}</div>
              <div className={`text-2xl font-extrabold ${cfg.text}`}>{counts[s.key]}</div>
              <div className="text-xs text-gray-500 mt-0.5">{s.label}</div>
            </button>
          );
        })}
      </div>

      {/* Orders */}
      {filtered.length === 0 ? (
        <div className="bg-white border border-gray-200 rounded-2xl p-12 text-center text-gray-400">
          <div className="text-5xl mb-3">🎉</div>
          <p className="font-medium">No orders in this category</p>
          <p className="text-sm mt-1">All caught up!</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 xl:grid-cols-2 gap-4">
          {filtered.map(order => {
            const cfg    = STATUS_CFG[order.status];
            const action = NEXT_ACTION[order.status];
            const isExpanded = expandedId === order.id;

            return (
              <div
                key={order.id}
                className={`bg-white border-2 rounded-2xl overflow-hidden transition-all ${
                  order.status === 'ready'
                    ? 'border-green-400 shadow-green-100 shadow-md'
                    : order.status === 'preparing'
                      ? 'border-amber-300'
                      : 'border-gray-200'
                }`}
              >
                {/* Card header */}
                <div className={`px-5 py-3 flex items-center justify-between ${cfg.bg}`}>
                  <div className="flex items-center gap-3">
                    <div className="text-center">
                      <div className={`text-2xl font-extrabold ${cfg.text}`}>#{order.token}</div>
                      <div className="text-xs text-gray-500">token</div>
                    </div>
                    <div>
                      <p className="font-semibold text-gray-900 text-sm">{order.customer}</p>
                      <p className="text-xs text-gray-500">
                        {order.table} · {timeAgo(order.placedAt)}
                      </p>
                    </div>
                  </div>
                  <div className="flex items-center gap-2">
                    <span className={`text-xs font-bold px-3 py-1 rounded-full ${cfg.bg} ${cfg.text} border ${cfg.border}`}>
                      <span className={`inline-block w-1.5 h-1.5 rounded-full ${cfg.dot} mr-1.5 ${order.status !== 'served' ? 'animate-pulse' : ''}`} />
                      {cfg.label}
                    </span>
                    <button
                      onClick={() => setExpandedId(isExpanded ? null : order.id)}
                      className="text-gray-400 hover:text-gray-600 text-lg"
                    >
                      {isExpanded ? '▲' : '▼'}
                    </button>
                  </div>
                </div>

                {/* Items list */}
                <div className="px-5 py-3 border-b border-gray-100">
                  <div className="flex flex-col gap-1">
                    {order.items.map((item, i) => (
                      <div key={i} className="flex justify-between text-sm">
                        <span className="text-gray-700">{item.name} × {item.qty}</span>
                        <span className="text-gray-500">₹{item.price * item.qty}</span>
                      </div>
                    ))}
                  </div>
                  {order.note && (
                    <div className="mt-2 bg-yellow-50 border border-yellow-200 rounded-lg px-3 py-1.5 text-xs text-yellow-800">
                      📝 Note: {order.note}
                    </div>
                  )}
                </div>

                {/* Expanded details */}
                {isExpanded && (
                  <div className="px-5 py-3 border-b border-gray-100 bg-gray-50 text-sm flex flex-col gap-1.5">
                    <div className="flex justify-between text-gray-500">
                      <span>Order ID</span><span className="font-medium text-gray-700">{order.id}</span>
                    </div>
                    <div className="flex justify-between text-gray-500">
                      <span>Phone</span><span className="font-medium text-gray-700">{order.phone}</span>
                    </div>
                    <div className="flex justify-between text-gray-500">
                      <span>Mode</span>
                      <span className="font-medium text-gray-700 capitalize">{order.mode}</span>
                    </div>
                    <div className="flex justify-between font-semibold text-gray-900 pt-1 border-t border-gray-200 mt-1">
                      <span>Total</span><span className="text-red-600">₹{order.total}</span>
                    </div>
                  </div>
                )}

                {/* Actions */}
                <div className="px-5 py-3 flex gap-2">
                  {/* Next status button */}
                  {action.next && (
                    <button
                      onClick={() => updateStatus(order.id, action.next)}
                      className={`flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl text-white text-sm font-semibold transition-colors ${action.color}`}
                    >
                      <span>{action.icon}</span>
                      {action.label}
                    </button>
                  )}

                  {/* Call token button - only when ready */}
                  {order.status === 'ready' && (
                    <button
                      onClick={() => callToken(order.token, order.table)}
                      className="flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl bg-blue-600 hover:bg-blue-700 text-white text-sm font-semibold transition-colors"
                    >
                      📢 Call Token
                    </button>
                  )}

                  {/* Completed state */}
                  {order.status === 'served' && (
                    <div className="flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl bg-gray-100 text-gray-400 text-sm font-medium">
                      🎉 Completed
                    </div>
                  )}
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}
